      "translation": "Iemesls",
      "explanation": "der Grund visbiežāk nozīmē iemeslu. Frāze aus diesem Grund nozīmē “šī iemesla dēļ”. Grund var nozīmēt arī pamatu vai grunti, uz kā kaut kas stāv. Dabā tas var nozīmēt zemi vai grunti. Ūdens kontekstā Grund var nozīmēt dibenu, piemēram ezera dibenu. Tāpēc šis vārds ir ļoti atkarīgs no konteksta.",
      "examples": [
        {
          "de": "Was ist der Grund?",
          "lv": "Kāds ir iemesls?"
        },
        {
          "de": "Aus diesem Grund bleibe ich zu Hause.",
          "lv": "Šī iemesla dēļ es palieku mājās."
        },
        {
          "de": "Der Grund des Problems ist klar.",
          "lv": "Problēmas iemesls ir skaidrs."
        },
        {
          "de": "Das Haus steht auf festem Grund.",
          "lv": "Māja stāv uz stingra pamata."
        },
        {
          "de": "Der Boden hat einen sandigen Grund.",
          "lv": "Zemei ir smilšaina grunts."
        },
        {
          "de": "Am Grund des Sees ist es dunkel.",
          "lv": "Ezera dibenā ir tumšs."
        }
      ],
      "comparison": [
        {
          "word": "der Grund",
          "meaning": "iemesls / pamats / grunts / dibens",
          "example": "Aus diesem Grund komme ich nicht. = Šī iemesla dēļ es nenākšu."
        },
        {
          "word": "die Ursache",
          "meaning": "cēlonis",
          "example": "Die Ursache ist unbekannt. = Cēlonis nav zināms."
        },
        {
          "word": "der Anlass",
          "meaning": "iemesls / notikuma pamats",
          "example": "Der Anlass war ein Fest. = Iemesls bija svētki."
        },
        {
          "word": "der Boden",
          "meaning": "zeme / grīda",
          "example": "Der Boden ist nass. = Grīda ir slapja."
        },
        {
          "word": "der Seegrund",
          "meaning": "ezera dibens",
          "example": "Der Seegrund ist dunkel. = Ezera dibens ir tumšs."
        }
      ],
      "tip": {
        "leftBlocks": [
          {
            "text": "aus diesem Grund ir ļoti bieža frāze un nozīmē “šī iemesla dēļ”."
          },
          {
            "text": "Ar māju, zemi vai ezeru Grund var nozīmēt pamatu, grunti vai dibenu."
          }
        ]
      },
      "important": {
        "text": "Grund nav tikai iemesls.",
        "example": "Grund des Problems = problēmas iemesls. fester Grund = stingrs pamats. Grund des Sees = ezera dibens."
      },
